require('dotenv').config();
const express = require('express');
const app = express();
const port = process.env.PORT;

app.use(express.static(__dirname));

app.get('/', (req, res) => {
  res.sendFile(__dirname + '/index.html');
});

app.get('/api/health', (req, res) => {
  res.status(200).send('OK');
});

app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});

:root {
  --primary-color: #333;
  --accent-color: #007bff;
  --background-color: #f9f9f9;
  --text-color: #fff;
  --border-radius: 16px;
  --box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
  --spacing: 16px;
}

body {
  font-family: 'Montserrat', sans-serif;
  background-image: linear-gradient(120deg, #fdfbfb 0%, #ebedee 100%);
  background-size: 100% 100%;
  height: 100vh;
  margin: 0;
  display: flex;
  justify-content: center;
  align-items: center;
}

.container {
  background-color: var(--background-color);
  padding: var(--spacing);
  border-radius: var(--border-radius);
  box-shadow: var(--box-shadow);
  width: 400px;
}

h1 {
  color: var(--primary-color);
  text-align: center;
}

#todo-input {
  width: 100%;
  padding: var(--spacing);
  border: none;
  border-radius: var(--border-radius);
  box-shadow: var(--box-shadow);
  font-size: 16px;
}

#add-btn {
  background-color: var(--accent-color);
  color: var(--text-color);
  padding: var(--spacing);
  border: none;
  border-radius: var(--border-radius);
  cursor: pointer;
}

#add-btn:hover {
  transform: scale(0.96);
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

#todo-list {
  list-style: none;
  padding: 0;
  margin: 0;
}

#todo-list li {
  padding: var(--spacing);
  border-bottom: 1px solid #ccc;
}

#todo-list li:last-child {
  border-bottom: none;
}

#download-btn {
  background-color: var(--accent-color);
  color: var(--text-color);
  padding: var(--spacing);
  border: none;
  border-radius: var(--border-radius);
  cursor: pointer;
}

#download-btn:hover {
  transform: scale(0.96);
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

#history-panel {
  margin-top: var(--spacing);
}

.copied {
  position: absolute;
  background-color: var(--accent-color);
  color: var(--text-color);
  padding: var(--spacing);
  border-radius: var(--border-radius);
  opacity: 0;
  transition: opacity 0.3s;
}

.copied.show {
  opacity: 1;
}

const todoInput = document.getElementById('todo-input');
const addBtn = document.getElementById('add-btn');
const todoList = document.getElementById('todo-list');
const downloadBtn = document.getElementById('download-btn');
const historyPanel = document.getElementById('history-panel');

let todos = [];
let history = [];

// Load sample data
todos = ['Buy groceries', 'Do laundry', 'Finish project'];
renderTodoList();

// Debounce input
let debounceTimeout;
todoInput.addEventListener('input', () => {
  clearTimeout(debounceTimeout);
  debounceTimeout = setTimeout(() => {
    const newTodo = todoInput.value.trim();
    if (newTodo) {
      todos.push(newTodo);
      renderTodoList();
      history.push({ action: 'add', todo: newTodo });
      renderHistoryPanel();
      todoInput.value = '';
    }
  }, 150);
});

// Add todo on enter key press
todoInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') {
    addBtn.click();
  }
});

// Add todo on button click
addBtn.addEventListener('click', () => {
  const newTodo = todoInput.value.trim();
  if (newTodo) {
    todos.push(newTodo);
    renderTodoList();
    history.push({ action: 'add', todo: newTodo });
    renderHistoryPanel();
    todoInput.value = '';
  }
});

// Download todos as file
downloadBtn.addEventListener('click', () => {
  const blob = new Blob([todos.join('\n')], { type: 'text/plain' });
  const link = document.createElement('a');
  link.href = URL.createObjectURL(blob);
  link.download = 'todos.txt';
  link.click();
});

// Render todo list
function renderTodoList() {
  todoList.innerHTML = '';
  todos.forEach((todo, index) => {
    const li = document.createElement('li');
    li.textContent = todo;
    li.addEventListener('click', () => {
      navigator.clipboard.writeText(todo);
      const copied = document.createElement('span');
      copied.textContent = 'Copied!';
      copied.classList.add('copied');
      li.appendChild(copied);
      setTimeout(() => {
        copied.classList.remove('show');
        setTimeout(() => {
          copied.remove();
        }, 300);
      }, 1000);
    });
    todoList.appendChild(li);
  });
}

// Render history panel
function renderHistoryPanel() {
  historyPanel.innerHTML = '';
  history.slice(-10).forEach((item) => {
    const p = document.createElement('p');
    p.textContent = `${item.action} ${item.todo}`;
    historyPanel.appendChild(p);
  });
}

// Keyboard shortcuts
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    todoInput.value = '';
  } else if (e.key === 'z' && e.ctrlKey) {
    if (history.length) {
      const lastAction = history.pop();
      if (lastAction.action === 'add') {
        todos.pop();
        renderTodoList();
        renderHistoryPanel();
      }
    }
  }
});
